(window.webpackJsonp=window.webpackJsonp||[]).push([[271],{566:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">seq</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxDepthAfterSplit = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">seq</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> initTag=<span class=\\"hljs-string\\">\'B\'</span>\\n  <span class=\\"hljs-keyword\\">let</span> value={\\n    <span class=\\"hljs-attr\\">A</span>:<span class=\\"hljs-number\\">0</span>,\\n    <span class=\\"hljs-attr\\">B</span>:<span class=\\"hljs-number\\">1</span>\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> resolve(seq,initTag)\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">resolve</span>(<span class=\\"hljs-params\\">string,lastTag</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> curTag=lastTag===<span class=\\"hljs-string\\">\'A\'</span> ? <span class=\\"hljs-string\\">\'B\'</span> : <span class=\\"hljs-string\\">\'A\'</span>\\n    <span class=\\"hljs-keyword\\">let</span> res=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;string.length;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(string[i]===<span class=\\"hljs-string\\">\\"(\\"</span>){\\n        <span class=\\"hljs-keyword\\">let</span> id=i+<span class=\\"hljs-number\\">1</span>\\n        <span class=\\"hljs-keyword\\">let</span> nxtStr=<span class=\\"hljs-string\\">\'\'</span>\\n        <span class=\\"hljs-keyword\\">let</span> count=<span class=\\"hljs-number\\">1</span>\\n        res[i]=value[curTag]\\n        <span class=\\"hljs-keyword\\">while</span>(<span class=\\"hljs-literal\\">true</span>){\\n          <span class=\\"hljs-keyword\\">if</span>(string[id]===<span class=\\"hljs-string\\">\'(\'</span>)count++\\n          <span class=\\"hljs-keyword\\">else</span> count--\\n          <span class=\\"hljs-keyword\\">if</span>(count===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">break</span>\\n          nxtStr+=string[id]\\n          id++\\n        }\\n        <span class=\\"hljs-keyword\\">let</span> nxtRes=resolve(nxtStr,curTag)\\n        res=res.concat(nxtRes)\\n        i=id\\n        res[i]=value[curTag]\\n      }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"maximum-nesting-depth-of-two-valid-parentheses-strings","hasThinking":false,"content":"<p><strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32 </strong>\u5b9a\u4e49\uff1a\u5bf9\u4e8e\u6bcf\u4e2a\u5de6\u62ec\u53f7\uff0c\u90fd\u80fd\u627e\u5230\u4e0e\u4e4b\u5bf9\u5e94\u7684\u53f3\u62ec\u53f7\uff0c\u53cd\u4e4b\u4ea6\u7136\u3002\u8be6\u60c5\u53c2\u89c1\u9898\u672b\u300c<strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32</strong>\u300d\u90e8\u5206\u3002</p>\\n\\n<p><strong>\u5d4c\u5957\u6df1\u5ea6</strong> <code>depth</code> \u5b9a\u4e49\uff1a\u5373\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\u5d4c\u5957\u7684\u5c42\u6570\uff0c<code>depth(A)</code> \u8868\u793a\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32 <code>A</code> \u7684\u5d4c\u5957\u6df1\u5ea6\u3002\u8be6\u60c5\u53c2\u89c1\u9898\u672b\u300c<strong>\u5d4c\u5957\u6df1\u5ea6</strong>\u300d\u90e8\u5206\u3002</p>\\n\\n<p>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\u7c7b\u578b\u4e0e\u5bf9\u5e94\u7684\u5d4c\u5957\u6df1\u5ea6\u8ba1\u7b97\u65b9\u6cd5\u5982\u4e0b\u56fe\u6240\u793a\uff1a</p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/04/01/1111.png\\" style=\\"height: 152px; width: 600px;\\"></p>\\n\\n<p>&nbsp;</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a\u300c\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\u300d <code>seq</code>\uff0c\u8bf7\u4f60\u5c06\u5176\u5206\u6210\u4e24\u4e2a\u4e0d\u76f8\u4ea4\u7684\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\uff0c<code>A</code> \u548c&nbsp;<code>B</code>\uff0c\u5e76\u4f7f\u8fd9\u4e24\u4e2a\u5b57\u7b26\u4e32\u7684\u6df1\u5ea6\u6700\u5c0f\u3002</p>\\n\\n<ul>\\n\\t<li>\u4e0d\u76f8\u4ea4\uff1a\u6bcf\u4e2a <code>seq[i]</code> \u53ea\u80fd\u5206\u7ed9 <code>A</code> \u548c <code>B</code> \u4e8c\u8005\u4e2d\u7684\u4e00\u4e2a\uff0c\u4e0d\u80fd\u65e2\u5c5e\u4e8e <code>A</code> \u4e5f\u5c5e\u4e8e <code>B</code> \u3002</li>\\n\\t<li><code>A</code> \u6216 <code>B</code> \u4e2d\u7684\u5143\u7d20\u5728\u539f\u5b57\u7b26\u4e32\u4e2d\u53ef\u4ee5\u4e0d\u8fde\u7eed\u3002</li>\\n\\t<li><code>A.length + B.length = seq.length</code></li>\\n\\t<li>\u6df1\u5ea6\u6700\u5c0f\uff1a<code>max(depth(A), depth(B))</code>&nbsp;\u7684\u53ef\u80fd\u53d6\u503c\u6700\u5c0f\u3002&nbsp;</li>\\n</ul>\\n\\n<p>\u5212\u5206\u65b9\u6848\u7528\u4e00\u4e2a\u957f\u5ea6\u4e3a <code>seq.length</code> \u7684\u7b54\u6848\u6570\u7ec4 <code>answer</code> \u8868\u793a\uff0c\u7f16\u7801\u89c4\u5219\u5982\u4e0b\uff1a</p>\\n\\n<ul>\\n\\t<li><code>answer[i] = 0</code>\uff0c<code>seq[i]</code> \u5206\u7ed9 <code>A</code> \u3002</li>\\n\\t<li><code>answer[i] = 1</code>\uff0c<code>seq[i]</code> \u5206\u7ed9 <code>B</code> \u3002</li>\\n</ul>\\n\\n<p>\u5982\u679c\u5b58\u5728\u591a\u4e2a\u6ee1\u8db3\u8981\u6c42\u7684\u7b54\u6848\uff0c\u53ea\u9700\u8fd4\u56de\u5176\u4e2d\u4efb\u610f <strong>\u4e00\u4e2a </strong>\u5373\u53ef\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>seq = &quot;(()())&quot;\\n<strong>\u8f93\u51fa\uff1a</strong>[0,1,1,1,1,0]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>seq = &quot;()(())()&quot;\\n<strong>\u8f93\u51fa\uff1a</strong>[0,0,0,1,1,0,1,1]\\n<strong>\u89e3\u91ca\uff1a</strong>\u672c\u793a\u4f8b\u7b54\u6848\u4e0d\u552f\u4e00\u3002\\n\u6309\u6b64\u8f93\u51fa A = &quot;()()&quot;, B = &quot;()()&quot;, max(depth(A), depth(B)) = 1\uff0c\u5b83\u4eec\u7684\u6df1\u5ea6\u6700\u5c0f\u3002\\n\u50cf [1,1,1,0,0,1,1,1]\uff0c\u4e5f\u662f\u6b63\u786e\u7ed3\u679c\uff0c\u5176\u4e2d A = &quot;()()()&quot;, B = &quot;()&quot;, max(depth(A), depth(B)) = 1 \u3002 \\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;&nbsp;seq.size &lt;= 10000</code></li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\uff1a</strong></p>\\n\\n<pre>\u4ec5\u7531&nbsp;<code>&quot;(&quot;</code> \u548c&nbsp;<code>&quot;)&quot;</code>&nbsp;\u6784\u6210\u7684\u5b57\u7b26\u4e32\uff0c\u5bf9\u4e8e\u6bcf\u4e2a\u5de6\u62ec\u53f7\uff0c\u90fd\u80fd\u627e\u5230\u4e0e\u4e4b\u5bf9\u5e94\u7684\u53f3\u62ec\u53f7\uff0c\u53cd\u4e4b\u4ea6\u7136\u3002\\n\u4e0b\u8ff0\u51e0\u79cd\u60c5\u51b5\u540c\u6837\u5c5e\u4e8e\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\uff1a\\n\\n  1. \u7a7a\u5b57\u7b26\u4e32\\n  2. \u8fde\u63a5\uff0c\u53ef\u4ee5\u8bb0\u4f5c&nbsp;<code>AB</code>\uff08<code>A</code> \u4e0e <code>B</code> \u8fde\u63a5\uff09\uff0c\u5176\u4e2d&nbsp;<code>A</code>&nbsp;\u548c&nbsp;<code>B</code>&nbsp;\u90fd\u662f\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\\n  3. \u5d4c\u5957\uff0c\u53ef\u4ee5\u8bb0\u4f5c&nbsp;<code>(A)</code>\uff0c\u5176\u4e2d&nbsp;<code>A</code>&nbsp;\u662f\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\\n</pre>\\n\\n<p><strong>\u5d4c\u5957\u6df1\u5ea6\uff1a</strong></p>\\n\\n<pre>\u7c7b\u4f3c\u5730\uff0c\u6211\u4eec\u53ef\u4ee5\u5b9a\u4e49\u4efb\u610f\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32 <code>s</code> \u7684 <strong>\u5d4c\u5957\u6df1\u5ea6</strong>&nbsp;<code>depth(S)</code>\uff1a\\n\\n  1.<code> s</code> \u4e3a\u7a7a\u65f6\uff0c<code>depth(&quot;&quot;) = 0</code>\\n<code>  2. s</code> \u4e3a <code>A</code> \u4e0e <code>B</code> \u8fde\u63a5\u65f6\uff0c<code>depth(A + B) = max(depth(A), depth(B))</code>\uff0c\u5176\u4e2d&nbsp;<code>A</code> \u548c&nbsp;<code>B</code>&nbsp;\u90fd\u662f\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\\n<code>  3. s</code> \u4e3a\u5d4c\u5957\u60c5\u51b5\uff0c<code>depth(&quot;(&quot; + A + &quot;)&quot;) = 1 + depth(A)</code>\uff0c\u5176\u4e2d <code>A</code> \u662f\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\\n\\n\u4f8b\u5982\uff1a<code>&quot;&quot;</code>\uff0c<code>&quot;()()&quot;</code>\uff0c\u548c&nbsp;<code>&quot;()(()())&quot;</code>&nbsp;\u90fd\u662f\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\uff0c\u5d4c\u5957\u6df1\u5ea6\u5206\u522b\u4e3a 0\uff0c1\uff0c2\uff0c\u800c&nbsp;<code>&quot;)(&quot;</code> \u548c&nbsp;<code>&quot;(()&quot;</code>&nbsp;\u90fd\u4e0d\u662f\u6709\u6548\u62ec\u53f7\u5b57\u7b26\u4e32\u3002\\n</pre>\\n","title":"1111. \u6709\u6548\u62ec\u53f7\u7684\u5d4c\u5957\u6df1\u5ea6","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u4e8c\u5206\u67e5\u627e"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1111"}')}}]);